        int greenComponent = (rgb >> 8) & 0xFF;
        int blueComponent = rgb & 0xFF;
        Assert.assertEquals(r, redComponent);
        Assert.assertEquals(g, greenComponent);
        Assert.assertEquals(b, blueComponent);
    }

