public class HashImageGeneratorTest {

    @Test
    public void testGenerateCreatesAccurateSymmetricImageFromHashDigest() throws NoSuchAlgorithmException {
        // Preconditions setup
        String content = "testContent";
        String algorithm = "SHA-256";
        MessageDigest md = MessageDigest.getInstance(algorithm);
        byte[] digest = md.digest(content.getBytes(java.nio.charset.StandardCharsets.UTF_8));

        int gridVerticalNum = 8;
        Color bgColor = Color.WHITE;
        Color fgColor = Color.BLACK;

        // Build the generator using the Builder
        HashImageGenerator generator = new HashImageGenerator.Builder(digest)
                .gridVerticalNum(gridVerticalNum)
                .bgColor(bgColor)
                .fgColor(fgColor)
                .build();

        // Expected Results verification
        BufferedImage image = generator.generate();

        // Check image dimensions
        assertEquals(gridVerticalNum, image.getWidth());
        assertEquals(gridVerticalNum, image.getHeight());

        // Verify symmetry and coloring based on least significant bit of digest bytes
        int gridHorizontalNum = (gridVerticalNum + 1) >> 1;
        for (int h = 0; h < gridHorizontalNum; h++) {
            for (int v = 0; v < gridVerticalNum; v++) {
                int pos = gridVerticalNum * h + v;
                int expectedRGB = ((digest[pos] & 1) == 1) ? fgColor.getRGB() : bgColor.getRGB();

                // Current grid cell
                assertEquals(expectedRGB, image.getRGB(h, v));
                // Symmetric grid cell across mid-vertical-line
                assertEquals(expectedRGB, image.getRGB(gridVerticalNum - h - 1, v));
            }
        }
    }
}

